from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an athlete (or related entities) into a single,
    fluent sentence. Handles a variety of predicates with more natural phrasing and
    combines multiple triples using relative clauses where appropriate.
    """
    if not triples:
        return ""

    # Helper to decide article for objects that look like proper nouns
    def needs_article(obj: str) -> bool:
        return not obj[0].isupper() and not obj.replace(" ", "").replace("-", "").isdigit()

    # Mapping of predicates to functions that return a clause (without leading subject)
    def clause_for(triple: Triple) -> str:
        s, p, o = triple.subject, triple.predicate, triple.object
        # Special handling for single‑triple cases that need a full sentence
        if len(triples) == 1:
            if p == "demonym":
                return f"The demonym for {s} is {o}"
            if p == "ethnicGroup":
                return f"{o} are an ethnic group in {s}"
            if p == "language":
                return f"The language spoken in {s} is {o}"
            if p == "officialLanguage":
                return f"The official language of {s} is {o}"
            if p == "currency":
                return f"The currency of {s} is the {o}"
        # General predicate handling
        if p in {"league"}:
            return f"plays in the {o} league"
        if p == "manager":
            return f"is managed by {o}"
        if p == "position":
            return f"holds the position of {o}"
        if p == "ground" or p == "stadium":
            return f"plays at {o}"
        if p == "birthDate":
            return f"was born on {o}"
        if p == "birthPlace":
            return f"was born in {o}"
        if p == "birthYear":
            return f"was born in {o}"
        if p == "club":
            return f"played for {o}"
        if p == "currentclub" or p == "currentteam":
            return f"currently plays for {o}"
        if p == "formerTeam":
            return f"formerly played for {o}"
        if p == "draftTeam":
            return f"was drafted by {o}"
        if p == "draftYear":
            return f"was drafted in {o}"
        if p == "draftRound":
            return f"was selected in round {o}"
        if p == "draftPick":
            return f"was the {o}th pick"
        if p == "debutTeam":
            return f"made his debut with {o}"
        if p == "height":
            return f"is {o} metres tall"
        if p == "weight":
            return f"weighs {o} kilograms"
        if p == "youthclub":
            return f"started at youth club {o}"
        if p == "playerNumber":
            return f"wears number {o}"
        if p == "college":
            return f"attended {o}"
        if p == "coach":
            return f"is coached by {o}"
        if p == "owner":
            return f"is owned by {o}"
        if p == "generalManager":
            return f"has general manager {o}"
        if p in {"chairman", "leader", "leaderTitle"}:
            # Use a relative clause
            return f"whose {p} is {o}"
        if p == "city":
            return f"is based in {o}"
        if p == "anthem":
            return f"has the anthem \"{o}\""
        if p == "ethnicGroup":
            return f"has an ethnic group called {o}"
        if p == "language":
            return f"speaks {o}"
        if p == "officialLanguage":
            return f"has {o} as an official language"
        if p == "currency":
            return f"uses the {o} as its currency"
        if p == "demonym":
            return f"is referred to as {o}"
        if p == "season":
            return f"participated in the {o} season"
        if p == "mostChampions":
            return f"has the most championships: {o}"
        if p == "isPartOf":
            return f"is part of {o}"
        if p == "country":
            return f"is located in {o}"
        if p == "utcOffset":
            return f"has a UTC offset of {o}"
        if p == "timeZone":
            return f"is in the {o} time zone"
        if p == "areaTotal":
            return f"covers an area of {o}"
        if p == "foundingDate":
            return f"was founded on {o}"
        # Fallback generic wording
        return f"{p} {o}"

    # Build clauses
    subject = triples[0].subject
    clauses = []
    for triple in triples:
        clauses.append(clause_for(triple))

    # Combine clauses: first clause attaches directly to subject, subsequent ones as
    # relative clauses or additional information separated by commas.
    if len(clauses) == 1:
        sentence = f"{subject} {clauses[0]}."
    else:
        first, rest = clauses[0], clauses[1:]
        # Use commas and conjunctions for readability
        rest_sentence = ", ".join(rest)
        sentence = f"{subject} {first}, {rest_sentence}."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END
